const raw = $input.all()[0]?.json ?? {};
let payload = raw.query ?? {};
let parseError = false;

const rawQueryText = typeof raw.query === 'string' ? raw.query : '';

if (typeof payload === 'string') {
  try {
    payload = JSON.parse(payload);
  } catch (error) {
    payload = {};
    parseError = true;
  }
}

if (!payload || typeof payload !== 'object' || Array.isArray(payload)) {
  payload = {};
  parseError = true;
}

function str(value) {
  return String(value ?? '').trim();
}

function parseTrustedHints(value) {
  if (!value) return {};
  if (typeof value === 'string') {
    try {
      const parsed = JSON.parse(value);
      return parsed && typeof parsed === 'object' && !Array.isArray(parsed) ? parsed : {};
    } catch (error) {
      return {};
    }
  }
  return value && typeof value === 'object' && !Array.isArray(value) ? value : {};
}

function buildUrl(path, query) {
  const pairs = Object.entries(query).filter(([, value]) => str(value));
  if (!pairs.length) return 'https://open.feishu.cn/open-apis' + path;
  const queryString = pairs
    .map(([key, value]) => encodeURIComponent(key) + '=' + encodeURIComponent(String(value)))
    .join('&');
  return 'https://open.feishu.cn/open-apis' + path + '?' + queryString;
}

function normalizedKey(key) {
  return String(key || '').replace(/[^A-Za-z0-9]/g, '').toLowerCase();
}

const forbiddenContextKeys = new Set([
  'contexthints',
  'contextids',
  'contextid',
  'chatid',
  'allowedchatid',
  'containerid',
  'containeridtype',
  'threadid',
  'topicid',
  'referencedmessageid',
  'referencemessageid',
  'replytomessageid',
  'quotedmessageid',
  'parentmessageid',
  'currentmessageid',
  'messageid',
  'messageids',
  'rootid',
  'parentid'
]);
const contextIdPattern = /\b(?:oc|om|omt)_[A-Za-z0-9_-]+\b/;

function findForbiddenContextInput(value, path = '') {
  if (value == null) return '';
  if (typeof value === 'string') {
    return contextIdPattern.test(value) ? (path || 'query') : '';
  }
  if (typeof value !== 'object') return '';
  if (Array.isArray(value)) {
    for (let index = 0; index < value.length; index += 1) {
      const found = findForbiddenContextInput(value[index], path + '[' + index + ']');
      if (found) return found;
    }
    return '';
  }
  for (const [key, nested] of Object.entries(value)) {
    const nextPath = path ? path + '.' + key : key;
    if (forbiddenContextKeys.has(normalizedKey(key))) return nextPath;
    const found = findForbiddenContextInput(nested, nextPath);
    if (found) return found;
  }
  return '';
}

const aliases = {
  resolve: 'resolve_context',
  context: 'resolve_context',
  get_context: 'resolve_context',
  resolveContext: 'resolve_context'
};

const requestedAction = str(payload.action ?? payload.tool ?? payload.operation ?? 'resolve_context');
const mappedAction = aliases[requestedAction] || requestedAction || 'resolve_context';
const directContextInput = findForbiddenContextInput(payload) || (rawQueryText && contextIdPattern.test(rawQueryText) ? 'query' : '');
const action = directContextInput ? 'unknown_action' : (mappedAction === 'resolve_context' ? 'resolve_context' : 'unknown_action');

const rawLimit = Number(payload.limit ?? payload.pageSize ?? payload.page_size ?? 10);
const limit = Number.isFinite(rawLimit) ? Math.min(Math.max(Math.trunc(rawLimit), 1), 20) : 10;
const hints = parseTrustedHints(raw.trustedContextHintsJson);

const chatId = str(hints.chatId ?? hints.chat_id);
const currentMessageId = str(hints.currentMessageId ?? hints.current_message_id ?? hints.messageId ?? hints.message_id);
const referencedMessageId = str(
  hints.referencedMessageId ??
  hints.referenced_message_id ??
  hints.referenceMessageId ??
  hints.reference_message_id ??
  hints.replyToMessageId ??
  hints.reply_to_message_id ??
  hints.parentMessageId ??
  hints.parent_message_id ??
  hints.parentId ??
  hints.parent_id ??
  hints.rootId ??
  hints.root_id
);
const threadId = str(hints.threadId ?? hints.thread_id);
const rootId = str(hints.rootId ?? hints.root_id);
const parentId = str(hints.parentId ?? hints.parent_id);
const createTime = str(hints.createTime ?? hints.create_time ?? hints.time);

let contextType = 'none';
let contextPath = '';
let contextQuery = {};
let error = null;

if (directContextInput) {
  error = {
    code: 'DIRECT_CONTEXT_ID_FORBIDDEN',
    message: 'conversation_context_tools only accepts context IDs from trustedContextHintsJson; AI query must not include chatId, referencedMessageId, threadId, contextHints, or aliases.',
    retryable: false,
    field: directContextInput
  };
} else if (referencedMessageId) {
  contextType = 'reference';
  contextPath = '/im/v1/messages/mget';
  contextQuery = {
    message_ids: referencedMessageId
  };
} else if (threadId) {
  contextType = 'thread';
  contextPath = '/im/v1/messages';
  contextQuery = {
    container_id_type: 'thread',
    container_id: threadId,
    sort_type: 'ByCreateTimeAsc',
    page_size: limit
  };
} else if (chatId) {
  contextType = 'recent_chat';
  contextPath = '/im/v1/messages';
  contextQuery = {
    container_id_type: 'chat',
    container_id: chatId,
    sort_type: 'ByCreateTimeDesc',
    page_size: limit
  };
}

const contextUrl = error || !contextPath ? '' : buildUrl(contextPath, contextQuery);

return [{
  json: {
    action,
    requestedAction: mappedAction,
    supportedActions: ['resolve_context'],
    parseError,
    limit,
    chatId,
    currentMessageId,
    referencedMessageId,
    threadId,
    rootId,
    parentId,
    createTime,
    contextType,
    contextUrl,
    contextQuery,
    error
  }
}];

const input = $input.all()[0]?.json ?? {};
const request = $('Normalize').all()[0]?.json ?? {};

function asBoolean(value) {
  if (typeof value === 'boolean') return value;
  if (typeof value === 'string') return value.toLowerCase() === 'true';
  return Boolean(value);
}

function parseContent(value) {
  if (typeof value !== 'string') return value;
  const trimmed = value.trim();
  if (!trimmed) return '';
  try {
    return JSON.parse(trimmed);
  } catch (error) {
    return trimmed;
  }
}

function extractText(value) {
  if (value == null) return '';
  if (typeof value === 'string') return value.trim();
  if (Array.isArray(value)) return value.map(extractText).filter(Boolean).join(' ');
  if (typeof value !== 'object') return '';

  if (typeof value.text === 'string') return value.text.trim();
  if (typeof value.title === 'string' && Array.isArray(value.content)) {
    const body = extractText(value.content);
    return (value.title + (body ? ' ' + body : '')).trim();
  }
  if (Array.isArray(value.content)) return extractText(value.content);
  if (value.zh_cn) return extractText(value.zh_cn);
  if (value.en_us) return extractText(value.en_us);
  if (Array.isArray(value.elements)) return extractText(value.elements);
  if (Array.isArray(value.blocks)) return extractText(value.blocks);
  if (typeof value.user_name === 'string') return '@' + value.user_name.trim();
  if (typeof value.tag === 'string') {
    const tag = value.tag.toLowerCase();
    if (tag === 'img' || tag === 'image') return '[image]';
    if (tag === 'file') return '[file]';
    if (tag === 'audio') return '[audio]';
    if (tag === 'media' || tag === 'video') return '[video]';
    if (tag === 'emotion') return '[emoji]';
    if (tag === 'at' && typeof value.user_name === 'string') return '@' + value.user_name.trim();
  }
  if (typeof value.content === 'string') return extractText(parseContent(value.content));

  return '';
}

function messageText(message) {
  const rawContent = message.body?.content ?? message.content ?? '';
  const parsed = parseContent(rawContent);
  const text = extractText(parsed) || extractText(message.body) || extractText(message.content);
  if (text) return text;
  const msgType = String(message.msg_type ?? message.msgType ?? '').toLowerCase();
  return msgType ? '[' + msgType + ']' : '[non-text message]';
}

function normalizeMessages(messages) {
  if (!Array.isArray(messages)) return [];
  return messages.map((message) => {
    const senderId = String(
      message.sender?.id ??
      message.sender?.sender_id ??
      message.sender?.open_id ??
      message.sender_id ??
      ''
    ).trim();
    const senderName = String(
      message.sender?.name ??
      message.sender?.sender_name ??
      message.sender_name ??
      senderId
    ).trim();

    return {
      messageId: String(message.message_id ?? message.messageId ?? '').trim(),
      senderName,
      senderId,
      createTime: String(message.create_time ?? message.createTime ?? '').trim(),
      msgType: String(message.msg_type ?? message.msgType ?? '').trim(),
      text: messageText(message)
    };
  }).filter((message) => message.messageId).slice(0, request.limit);
}

function buildOutput(prefix, messages) {
  if (!messages.length) return prefix + ': no messages found.';
  const lines = messages.map((message, index) => {
    return String(index + 1) + '. ' + (message.senderName || message.senderId || 'Unknown') + ': ' + (message.text || '[non-text message]');
  });
  return [prefix, ...lines].join(String.fromCharCode(10));
}

const contextType = request.contextType || 'none';
const missingIdentifiersMessage = 'resolve_context needs referencedMessageId, threadId, or chatId.';
const config = {
  reference: {
    fetchLabel: 'referenced message',
    fetchCode: 'REFERENCE_FETCH_FAILED',
    notFoundCode: 'REFERENCE_NOT_FOUND',
    notFoundOutput: 'Referenced message not found or inaccessible.',
    notFoundMessage: 'No readable referenced message returned.',
    successPrefix: 'Resolved reference context',
    neverTruncated: true
  },
  thread: {
    fetchLabel: 'thread messages',
    fetchCode: 'THREAD_FETCH_FAILED',
    notFoundCode: 'THREAD_NOT_FOUND',
    notFoundOutput: 'Thread messages not found or inaccessible.',
    notFoundMessage: 'No readable thread messages returned.',
    successPrefix: 'Resolved thread context',
    neverTruncated: false
  },
  recent_chat: {
    fetchLabel: 'recent chat messages',
    fetchCode: 'CHAT_FETCH_FAILED',
    notFoundCode: 'CHAT_NOT_FOUND',
    notFoundOutput: 'Recent chat messages not found or inaccessible.',
    notFoundMessage: 'No readable recent chat messages returned.',
    successPrefix: 'Resolved recent chat context',
    neverTruncated: false
  }
}[contextType];

function finish({ ok, messages, output, error, truncated }) {
  return [{
    json: {
      ok,
      action: 'resolve_context',
      contextType: ok ? contextType : 'none',
      output,
      messages,
      limits: {
        limit: request.limit,
        truncated
      },
      error,
      meta: {
        chatId: request.chatId,
        currentMessageId: request.currentMessageId,
        referencedMessageId: request.referencedMessageId,
        threadId: request.threadId,
        rootId: request.rootId,
        parentId: request.parentId
      }
    }
  }];
}

if (!config || contextType === 'none' || !request.contextUrl) {
  return finish({
    ok: false,
    messages: [],
    output: missingIdentifiersMessage,
    truncated: false,
    error: {
      code: 'MISSING_CONTEXT_IDENTIFIERS',
      message: missingIdentifiersMessage,
      retryable: false
    }
  });
}

if (input.error) {
  const detail = typeof input.error === 'string' ? input.error : (input.error.message || JSON.stringify(input.error));
  return finish({
    ok: false,
    messages: [],
    output: 'Failed to fetch ' + config.fetchLabel + ': ' + detail,
    truncated: false,
    error: {
      code: config.fetchCode,
      message: detail,
      retryable: true
    }
  });
}

if (input.code && input.code !== 0) {
  const detail = input.msg || JSON.stringify(input);
  return finish({
    ok: false,
    messages: [],
    output: 'Failed to fetch ' + config.fetchLabel + ': ' + detail,
    truncated: false,
    error: {
      code: config.fetchCode,
      message: String(input.msg || 'request failed'),
      retryable: true
    }
  });
}

const rawMessages = input.messages ?? input.items ?? input.data?.messages ?? input.data?.items ?? [];
const messages = normalizeMessages(rawMessages);
const hasMore = asBoolean(input.has_more ?? input.data?.has_more ?? input.hasMore ?? input.data?.hasMore);
const truncated = config.neverTruncated ? false : (hasMore || (Array.isArray(rawMessages) && rawMessages.length > request.limit));

if (!messages.length) {
  return finish({
    ok: false,
    messages: [],
    output: config.notFoundOutput,
    truncated: false,
    error: {
      code: config.notFoundCode,
      message: config.notFoundMessage,
      retryable: false
    }
  });
}

return finish({
  ok: true,
  messages,
  output: buildOutput(config.successPrefix, messages),
  truncated,
  error: null
});

const request = $input.all()[0]?.json ?? {};
const output = request.error
  ? request.error.message
  : (request.parseError
    ? 'conversation_context_tools received invalid JSON input.'
    : 'conversation_context_tools does not support action: ' + (request.requestedAction || '(empty)') + '. Supported action: resolve_context.');

return [{
  json: {
    ok: false,
    action: request.error ? 'resolve_context' : (request.action || 'unknown_action'),
    contextType: 'none',
    output,
    messages: [],
    limits: {
      limit: request.limit || 10,
      truncated: false
    },
    error: request.error || {
      code: request.parseError ? 'INVALID_TOOL_INPUT' : 'UNSUPPORTED_ACTION',
      message: output,
      retryable: false
    },
    meta: {
      chatId: request.chatId || '',
      currentMessageId: request.currentMessageId || '',
      referencedMessageId: request.referencedMessageId || '',
      threadId: request.threadId || '',
      rootId: request.rootId || '',
      parentId: request.parentId || ''
    }
  }
}];
